// ─────────────────────────────────────────────────────────────────────────────
// src/pages/Login.jsx
// Login screen — TWO modes:
//   1. Demo role cards (quick login for testing)
//   2. Email + Password form (for any employee including newly created ones)
// ─────────────────────────────────────────────────────────────────────────────

import { useState } from "react";
import { Icon } from "../components/common";
import { EMPLOYEES_DATA } from "../data/mockData";
import { avatarColor } from "../utils/helpers";

const DEMO_USERS = [
  { ...EMPLOYEES_DATA[4], desc: "Full system access, manage everything" },
  { ...EMPLOYEES_DATA[1], desc: "Review approvals, generate reports" },
  { ...EMPLOYEES_DATA[0], desc: "Apply leave, view balance & status" },
];

const ROLE_STYLE = {
  admin: { bg: "#fef3c7", color: "#92400e" },
  hr: { bg: "#d1fae5", color: "#065f46" },
  employee: { bg: "#eef2ff", color: "#4f46e5" },
};

const Login = ({ onLogin, onLoginWithEmail }) => {
  const [mode, setMode] = useState("demo"); // "demo" or "email"
  const [selected, setSelected] = useState(null);

  // Email/Password form state
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleEmailLogin = async () => {
    setError("");
    if (!email.trim()) return setError("Email is required");
    if (!password.trim()) return setError("Password is required");

    setLoading(true);
    try {
      await onLoginWithEmail(email, password);
    } catch (err) {
      setError(err.message || "Invalid email or password");
    }
    setLoading(false);
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleEmailLogin();
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #0f172a 100%)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      <div style={{ width: "100%", maxWidth: 440 }}>
        {/* Logo + title */}
        <div style={{ textAlign: "center", marginBottom: 40 }}>
          <div
            style={{
              width: 60, height: 60,
              background: "linear-gradient(135deg,#4f46e5,#7c3aed)",
              borderRadius: 16,
              display: "flex", alignItems: "center", justifyContent: "center",
              margin: "0 auto 16px",
            }}
          >
            <Icon name="leave" size={28} color="#fff" />
          </div>
          <h1 style={{ fontFamily: "Syne", fontSize: 30, fontWeight: 800, color: "#fff" }}>
            LeaveFlow
          </h1>
          <p style={{ color: "#a5b4fc", fontSize: 14, marginTop: 6 }}>
            Employee Leave Management System
          </p>
        </div>

        {/* Glass card */}
        <div
          style={{
            background: "rgba(255,255,255,0.05)",
            backdropFilter: "blur(12px)",
            borderRadius: 20,
            padding: 28,
            border: "1px solid rgba(255,255,255,0.1)",
          }}
        >
          {/* Tab switcher */}
          <div style={{ display: "flex", gap: 0, marginBottom: 20, background: "rgba(255,255,255,0.06)", borderRadius: 10, padding: 3 }}>
            <button
              onClick={() => setMode("demo")}
              style={{
                flex: 1, padding: "9px 0", borderRadius: 8, border: "none", cursor: "pointer",
                fontSize: 13, fontWeight: 700, transition: "all 0.2s",
                background: mode === "demo" ? "rgba(79,70,229,0.8)" : "transparent",
                color: mode === "demo" ? "#fff" : "#94a3b8",
              }}
            >
              Demo Accounts
            </button>
            <button
              onClick={() => setMode("email")}
              style={{
                flex: 1, padding: "9px 0", borderRadius: 8, border: "none", cursor: "pointer",
                fontSize: 13, fontWeight: 700, transition: "all 0.2s",
                background: mode === "email" ? "rgba(79,70,229,0.8)" : "transparent",
                color: mode === "email" ? "#fff" : "#94a3b8",
              }}
            >
              Email Login
            </button>
          </div>

          {/* ─── DEMO MODE ─── */}
          {mode === "demo" && (
            <>
              <h2 style={{ color: "#fff", fontFamily: "Syne", fontWeight: 700, fontSize: 17, marginBottom: 6 }}>
                Select Demo Account
              </h2>
              <p style={{ color: "#94a3b8", fontSize: 13, marginBottom: 20 }}>
                Choose a role to explore the system
              </p>

              {DEMO_USERS.map((u) => {
                const rs = ROLE_STYLE[u.role] || ROLE_STYLE.employee;
                const isActive = selected?.id === u.id;
                return (
                  <div
                    key={u.id}
                    onClick={() => setSelected(u)}
                    style={{
                      display: "flex", alignItems: "center", gap: 14,
                      padding: "14px 16px", borderRadius: 12, cursor: "pointer", marginBottom: 10,
                      border: `1.5px solid ${isActive ? "#4f46e5" : "rgba(255,255,255,0.08)"}`,
                      background: isActive ? "rgba(79,70,229,0.2)" : "rgba(255,255,255,0.03)",
                      transition: "all 0.2s",
                    }}
                  >
                    <div className="avatar" style={{ background: avatarColor(u.id), width: 44, height: 44, fontSize: 14 }}>
                      {u.avatar}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ color: "#fff", fontWeight: 700, fontSize: 14 }}>{u.name}</div>
                      <div style={{ color: "#94a3b8", fontSize: 12, marginTop: 2 }}>{u.desc}</div>
                    </div>
                    <span style={{
                      padding: "3px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700,
                      background: rs.bg, color: rs.color, textTransform: "capitalize",
                    }}>
                      {u.role}
                    </span>
                  </div>
                );
              })}

              <button
                className="btn btn-primary"
                style={{
                  width: "100%", justifyContent: "center",
                  marginTop: 8, padding: "12px", fontSize: 15,
                  opacity: selected ? 1 : 0.5,
                }}
                onClick={() => selected && onLogin(selected)}
              >
                Sign In →
              </button>
            </>
          )}

          {/* ─── EMAIL MODE ─── */}
          {mode === "email" && (
            <>
              <h2 style={{ color: "#fff", fontFamily: "Syne", fontWeight: 700, fontSize: 17, marginBottom: 6 }}>
                Employee Login
              </h2>
              <p style={{ color: "#94a3b8", fontSize: 13, marginBottom: 20 }}>
                Sign in with your email and password
              </p>

              {/* Error message */}
              {error && (
                <div style={{
                  background: "rgba(239,68,68,0.15)", border: "1px solid rgba(239,68,68,0.3)",
                  borderRadius: 10, padding: "10px 14px", marginBottom: 16,
                  color: "#fca5a5", fontSize: 13, fontWeight: 600,
                }}>
                  {error}
                </div>
              )}

              {/* Email */}
              <div style={{ marginBottom: 14 }}>
                <label style={{ color: "#94a3b8", fontSize: 12, fontWeight: 600, display: "block", marginBottom: 6 }}>
                  EMAIL
                </label>
                <input
                  type="email"
                  placeholder="e.g. rahul@company.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  onKeyDown={handleKeyDown}
                  style={{
                    width: "100%", padding: "12px 14px", borderRadius: 10, border: "1.5px solid rgba(255,255,255,0.12)",
                    background: "rgba(255,255,255,0.06)", color: "#fff", fontSize: 14, outline: "none",
                    transition: "border 0.2s", boxSizing: "border-box",
                  }}
                  onFocus={(e) => e.target.style.borderColor = "#4f46e5"}
                  onBlur={(e) => e.target.style.borderColor = "rgba(255,255,255,0.12)"}
                />
              </div>

              {/* Password */}
              <div style={{ marginBottom: 20 }}>
                <label style={{ color: "#94a3b8", fontSize: 12, fontWeight: 600, display: "block", marginBottom: 6 }}>
                  PASSWORD
                </label>
                <input
                  type="password"
                  placeholder="Enter your password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  onKeyDown={handleKeyDown}
                  style={{
                    width: "100%", padding: "12px 14px", borderRadius: 10, border: "1.5px solid rgba(255,255,255,0.12)",
                    background: "rgba(255,255,255,0.06)", color: "#fff", fontSize: 14, outline: "none",
                    transition: "border 0.2s", boxSizing: "border-box",
                  }}
                  onFocus={(e) => e.target.style.borderColor = "#4f46e5"}
                  onBlur={(e) => e.target.style.borderColor = "rgba(255,255,255,0.12)"}
                />
              </div>

              {/* Sign in button */}
              <button
                className="btn btn-primary"
                style={{
                  width: "100%", justifyContent: "center",
                  padding: "12px", fontSize: 15,
                  opacity: loading ? 0.6 : 1,
                }}
                onClick={handleEmailLogin}
                disabled={loading}
              >
                {loading ? "Signing in..." : "Sign In →"}
              </button>

              {/* Hint */}
              <div style={{ marginTop: 16, padding: "10px 14px", background: "rgba(255,255,255,0.04)", borderRadius: 10, border: "1px solid rgba(255,255,255,0.06)" }}>
                <div style={{ color: "#64748b", fontSize: 11, fontWeight: 600, marginBottom: 4 }}>
                  DEFAULT PASSWORD FOR ALL ACCOUNTS
                </div>
                <div style={{ color: "#a5b4fc", fontSize: 13, fontWeight: 700, fontFamily: "monospace" }}>
                  password
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
